#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(fileURLToPath(new URL("..", import.meta.url)));
const read = (relative) => fs.readFileSync(path.join(root, relative), "utf8");
// MainWindowController is split across sibling `MainWindowController+*.swift` extension files
// (refactor: shrink the core file). Concat them so the `files.controller` checks below keep matching
// symbols wherever they now live.
const readGlob = (dir, prefix) => {
  const all = fs
    .readdirSync(path.join(root, dir))
    .filter((f) => f.startsWith(prefix) && f.endsWith(".swift"));
  // Keep the base `<prefix>.swift` first, then the `<prefix>+*.swift` extensions, so checks that use
  // greedy `[\s\S]*` to assert one symbol appears before another (production-before-smoke) still hold.
  const base = all.filter((f) => f === `${prefix}.swift`);
  const exts = all.filter((f) => f !== `${prefix}.swift`).sort();
  return [...base, ...exts].map((f) => read(path.join(dir, f))).join("\n");
};
const files = {
  package: read("Package.swift"),
  build: read("scripts/build.sh"),
  libGhosttyEnv: read("scripts/libghostty-env.sh"),
  packageApp: read("scripts/package-app.sh"),
  installApp: read("scripts/install-app.sh"),
  packageDmg: read("scripts/package-dmg.sh"),
  launchSmoke: read("scripts/launch-smoke.sh"),
  keyInputSmoke: read("scripts/key-input-smoke.sh"),
  appDelegate: read("Sources/Momenterm/AppDelegate.swift"),
  controller: readGlob("Sources/Momenterm", "MainWindowController"),
  fileTreeModel: read("Sources/Momenterm/FileTreeModel.swift"),
  textViews: read("Sources/Momenterm/NativeTextViews.swift"),
  contentRenderers: read("Sources/Momenterm/NativeContentRenderers.swift"),
  ansiRenderer: read("Sources/Momenterm/NativeAnsiRenderer.swift"),
  codePane: read("Sources/Momenterm/NativeCodePane.swift"),
  nativeTheme: read("Sources/Momenterm/NativeTheme.swift"),
  httpRunner: read("Sources/Momenterm/HttpRunnerController.swift"),
  httpClient: read("Sources/Momenterm/NativeHttpClient.swift"),
  syntax: read("Sources/Momenterm/NativeSyntaxHighlighting.swift"),
  libGhosttyView: read("Sources/Momenterm/LibGhosttyTerminalView.swift"),
  designSystem: read("Sources/Momenterm/NativeDesignSystem.swift"),
  keyInputSmokeSource: fs.readdirSync(path.join(root, "Sources/KeyInputSmoke")).filter((f) => f.endsWith(".swift")).sort().map((f) => read(path.join("Sources/KeyInputSmoke", f))).join("\n"),
  gitClient: read("Sources/Momenterm/NativeGitClient.swift"),
  reviewCore: read("Sources/Momenterm/NativeReviewCore.swift"),
  reviewTypes: read("Sources/Momenterm/NativeReviewTypes.swift"),
  sourceCollector: read("Sources/Momenterm/NativeSourceCollector.swift"),
  pty: read("Sources/Momenterm/NativePtyManager.swift"),
  terminalCore: read("Sources/Momenterm/NativeTerminalCore.swift"),
  coreSmoke: read("Sources/CoreSmoke/main.swift"),
  ptySmoke: read("Sources/PtySmoke/main.swift"),
  perfSmoke: read("Sources/PerfSmoke/main.swift")
};
const all = Object.values(files).join("\n");
// After the native workbench refactor, symbols that used to live in
// MainWindowController.swift now live in sibling files (NativeTextViews,
// NativeContentRenderers, NativeAnsiRenderer, NativeCodePane, NativeTheme,
// HttpRunnerController). These merged views let the parity checks below keep
// asserting the same behavior against whichever file now owns each symbol.
const controllerAndTextViews = files.controller + "\n" + files.textViews;
const controllerAndCodeViews = files.controller + "\n" + files.textViews + "\n" + files.codePane;
const controllerAndContent = files.controller + "\n" + files.contentRenderers;
const controllerAndHttp = files.controller + "\n" + files.httpRunner + "\n" + files.codePane;
// FileTree row model + collapse-filter logic moved into the FileTreeModel collaborator (Phase 3).
const controllerAndFileTree = files.controller + "\n" + files.fileTreeModel;
const failures = [];
const findInFilesWidthHelper = files.controller.match(/(?:private )?func constrainFindInFilesRowWidth\(_ view: NSView\) \{[\s\S]*?\n    \}/)?.[0] || "";
// Terminate at each function's own member-indent closing brace so the extraction survives the
// Phase 2 split (functions moved into sibling files, changing adjacency).
const populateSearchOverlayBody = files.controller.match(/(?:private )?func populateSearchOverlay\(title: String, markers: \[String\]\) \{[\s\S]*?\n    \}/)?.[0] || "";
const mergedPromptContentBody = files.controller.match(/(?:private )?func mergedPromptContent\(title: String\) -> MergedPromptContent \{[\s\S]*?\n    \}/)?.[0] || "";

function check(name, ok, detail = "") {
  if (ok) {
    console.log(`ok - ${name}`);
  } else {
    console.error(`not ok - ${name}${detail ? `: ${detail}` : ""}`);
    failures.push(name);
  }
}

function has(source, pattern) {
  return pattern instanceof RegExp ? pattern.test(source) : source.includes(pattern);
}

const forbidden = [
  "import Web" + "Kit",
  "WK" + "WebView",
  "WK" + "ScriptMessage",
  "WK" + "UserContentController",
  "window.web" + "kit",
  "evaluate" + "JavaScript",
  "loadHTML" + "String",
  "Native" + "HTMLRenderer",
  "client" + "Script",
  "inner" + "HTML",
  "-framework Web" + "Kit",
  ".linkedFramework(\"Web" + "Kit\")",
  "monacori" + "/dist",
  "monacori" + "-bridge",
  "MONACORI" + "_DIST",
  "NODE" + "_BIN",
  "buildDiff" + "Review("
];
for (const marker of forbidden) {
  check(`forbidden non-native marker absent: ${marker}`, !all.includes(marker));
}

